SELECT DEP_REQ_SEQ AS depReqSeq, FAMILY_ID AS familyId, PUR_ITEM_SEQ AS purItemSeq, STORE_INFO AS storeInfo, AMOUNT AS amount, REQ_STATUS AS reqStatus, REQ_DESC AS reqDesc, REG_ID AS regId, REG_DT AS requestDt, UPD_ID AS updId, UPD_DT AS updDt FROM SCM_DEPOSIT_REQUEST_MST WHERE FAMILY_ID = #{familyId}
AND REG_ID = #{regId}
ORDER BY REG_DT DESC, DEP_REQ_SEQ DESC
